/* =========================================================
  HELPERS
========================================================= */

function getCountryName(code) {
  if (!code) return "—";
  const k = String(code).toLowerCase().trim();
  const c = countries.find((x) => String(x.code).toLowerCase() === k);
  return c ? c.name : k.toUpperCase();
}

function normalizeStatus(s) {
  return String(s || "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, " ");
}

function normalizeVisaStatus(estado) {
  const s = normalizeStatus(estado);

  if (s === "visa is not required") return "not_required";
  if (s === "prior authorization") return "prior_auth";
  if (s === "administrative entry requirement") return "admin_entry_req";
  if (s === "visa issued upon arrival") return "visa_on_arrival";
  if (s === "electronic visa") return "evisa";
  if (s === "visa is required") return "required";
  if (s === "entry prohibited") return "entry_prohibited";

  return "other";
}

function visaStatusLabel(estado) {
  const k = normalizeVisaStatus(estado);

  if (k === "not_required") return "Visa Is Not Required";
  if (k === "prior_auth") return "Prior Authorization";
  if (k === "admin_entry_req") return "Administrative Entry Requirement";
  if (k === "visa_on_arrival") return "Visa Issued Upon Arrival";
  if (k === "evisa") return "Electronic Visa";
  if (k === "required") return "Visa Is Required";
  if (k === "entry_prohibited") return "Entry prohibited";

  return estado ? String(estado).trim() : "—";
}

function visaCssClass(estado) {
  const k = normalizeVisaStatus(estado);

  if (k === "not_required") return "visa-free";
  if (k === "prior_auth") return "prior-auth";
  if (k === "admin_entry_req") return "admin-entry-req";
  if (k === "visa_on_arrival") return "visa-on-arrival";
  if (k === "evisa") return "evisa";
  if (k === "required") return "visa-required";
  if (k === "entry_prohibited") return "entry-prohibited";

  return "";
}

function visaLookup(passportCode, destinationCode, showDays = true) {
  if (!passportCode || !destinationCode) {
    return `<div class="visa-status">—</div><div class="visa-days">&nbsp;</div>`;
  }

  if (passportCode === destinationCode) {
    return `
      <div class="visa-status">Visa Is Not Required</div>
      <div class="visa-days">&nbsp;</div>
    `;
  }

  const dest = visaIndex.get(passportCode)?.get(destinationCode);
  if (!dest) {
    return `
      <div class="visa-status">No data.</div>
      <div class="visa-days">&nbsp;</div>
    `;
  }

  const estadoShown = visaStatusLabel(dest.estado);
  const dias = Number(dest.dias);

  const daysText =
    showDays && Number.isFinite(dias) && dias > 0 ? `${dias} days` : "&nbsp;";

  return `
    <div class="visa-status">${estadoShown}</div>
    <div class="visa-days">${daysText}</div>
  `;
}

function isVisaFreeFor(passportCode, destinationCode) {
  const dest = visaIndex.get(passportCode)?.get(destinationCode);
  return normalizeVisaStatus(dest?.estado) === "not_required";
}

function getCountryNotes(countryCode, passportCode) {
  const notes = [];

  if (
    isVisaFreeFor(passportCode, countryCode) &&
    VisaNotes?.[countryCode]?.note
  ) {
    notes.push(VisaNotes[countryCode].note);
  }

  if (ConflictsNotes?.[countryCode]?.note) {
    notes.push(ConflictsNotes[countryCode].note);
  }

  return notes;
}

/* =========================================================
  NAVIGATION 
========================================================= */

function hideAllMainSections() {
  document.querySelectorAll(DOM.mainSelector).forEach(m => {
    m.classList.remove("active");
    m.setAttribute("hidden", "");
  });
}

function showSection(id, activeLink = null) {
  hideAllMainSections();

  const target = el(id);
  if (target) {
    target.classList.add("active");
    target.removeAttribute("hidden");
  }

  document.querySelectorAll(DOM.navLinks).forEach(a => a.classList.remove("active"));
  if (activeLink) activeLink.classList.add("active");

  window.scrollTo(0, 0);
}

function backTo(id) { showSection(id); }
function goToSection(id) { showSection(id); }

/* =========================================================
  SELECTS
========================================================= */

function populateCountrySelects() {
  const sorted = [...countries].sort((a, b) => a.name.localeCompare(b.name));
  document.querySelectorAll('select[data-countries-select="1"]').forEach(select => {
    const firstOption = select.querySelector("option");
    select.innerHTML = "";
    if (firstOption) select.appendChild(firstOption);

    sorted.forEach(c => {
      const opt = document.createElement("option");
      opt.value = c.code;
      opt.textContent = c.name;
      select.appendChild(opt);
    });
  });
}

/* =========================================================
  RENDER HELPERS
========================================================= */

function renderVisaBlock(label, destinationCode, passport1, passport2) {
  const destinationName = getCountryName(destinationCode);
  const isFinal = String(label).toLowerCase().includes("final");
  const extraClass = isFinal ? "destino-final" : "";

  const renderPassportLine = (passportCode) => {
    if (!passportCode) return "";
    const passportName = getCountryName(passportCode);
    const visaText = visaLookup(passportCode, destinationCode, isFinal);

    return `
      <li style="margin-bottom:10px;">
        <b>Passport (${passportName}):</b>
        <ul style="list-style-type:circle; margin-left:20px;">
          <li>${visaText}</li>
        </ul>
      </li>
    `;
  };

  const passportForNotes =
    isVisaFreeFor(passport1, destinationCode) ? passport1 :
    (passport2 && isVisaFreeFor(passport2, destinationCode)) ? passport2 :
    passport1;

  const notes = getCountryNotes(destinationCode, passportForNotes);

  const notesHtml = notes.length ? `
    <div style="margin-top:8px;">
      <b>Notes</b>
      <ul style="list-style-type:disc; margin-left:20px; margin-top:6px;">
        ${notes.map(n => `<li>${n}</li>`).join("")}
      </ul>
      <div style="margin-left:20px; margin-top:8px; font-weight:600;">
        Consult the embassy’s official website for further information.
      </div>
    </div>
  ` : "";

  return `
    <div class="visa-block ${extraClass}">
      <b>${label} (${destinationName}):</b>
      <ul style="list-style-type:disc; padding-left:20px; margin:0;">
        ${renderPassportLine(passport1)}
        ${renderPassportLine(passport2)}
      </ul>
      ${notesHtml}
    </div>
  `;
}

/* =========================================================
  SINGLE TRIP
========================================================= */

function searchSingleTrip() {
  const passport1 = el(DOM.single.passport1)?.value || "";
  const passport2 = el(DOM.single.passport2)?.value || "";
  const departure = el(DOM.single.departure)?.value || "";
  const destination = el(DOM.single.destination)?.value || "";

  let connectionsSummaryHtml = "";
  for (let i = 1; i <= state.connectionCount; i++) {
    const c = el(`connection${i}`)?.value || "";
    connectionsSummaryHtml += `<p><b>${i}º Connection:</b> ${getCountryName(c)}</p>`;
  }

  el(DOM.single.resultText).innerHTML = `
    <p><b>Main Passport:</b> ${getCountryName(passport1)}</p>
    <p><b>Secondary Passport:</b> ${getCountryName(passport2)}</p>
    <p><b>Departure country:</b> ${getCountryName(departure)}</p>
    ${connectionsSummaryHtml}
    <p><b>Final Destination:</b> ${getCountryName(destination)}</p>
  `;

  let visasHtml = "";
  for (let i = 1; i <= state.connectionCount; i++) {
    const c = el(`connection${i}`)?.value || "";
    visasHtml += renderVisaBlock(`${i}º Connection`, c, passport1, passport2);
  }
  visasHtml += renderVisaBlock("Final Destination", destination, passport1, passport2);

  el(DOM.single.resultVisa).innerHTML = visasHtml;
  showSection(DOM.single.resultsMain);
}

function addConnection() {
  state.connectionCount++;
  const original = el(DOM.single.connection1);
  if (!original) return;

  const newSelect = original.cloneNode(true);
  newSelect.id = `connection${state.connectionCount}`;

  const wrapper = document.createElement("div");
  wrapper.className = "form-group";
  wrapper.id = `connection-wrap-${state.connectionCount}`;
  wrapper.innerHTML = `<label for="connection${state.connectionCount}">${state.connectionCount}º Connection:</label>`;
  wrapper.appendChild(newSelect);

  el(DOM.single.connectionsContainer).insertBefore(wrapper, el(DOM.single.connectionButtons));
}

function removeConnection() {
  if (state.connectionCount <= 1) return;
  el(`connection-wrap-${state.connectionCount}`)?.remove();
  state.connectionCount--;
}

/* =========================================================
  MULTI TRIP
========================================================= */

function renderNotesColumn(destinationCode, passport1, passport2) {
  const passportForNotes =
    isVisaFreeFor(passport1, destinationCode) ? passport1 :
    (passport2 && isVisaFreeFor(passport2, destinationCode)) ? passport2 :
    passport1;

  const notes = getCountryNotes(destinationCode, passportForNotes);
  if (!notes.length) return "—";

  return `
    <div style="text-align:left;">
      <b>Notes</b>
      <ul style="list-style-type:disc; margin:6px 0 0 18px; padding:0;">
        ${notes.map(n => `<li>${n}</li>`).join("")}
      </ul>
      <div style="margin-top:8px; font-weight:600;">
        Consult the embassy’s official website for further information.
      </div>
    </div>
  `;
}

function searchMultiTrip() {
  const passport1 = el(DOM.multi.passport1)?.value || "";
  const passport2 = el(DOM.multi.passport2)?.value || "";

  let tableHtml = `
    <section class="resultado-box" aria-label="Search summary">
      <h3 class="resultado-titulo-interno">Search Summary</h3>
      <div class="passport-box-MT">
        <p><b>Main Passport:</b> ${getCountryName(passport1)}</p>
        <p><b>Secondary Passport:</b> ${passport2 ? getCountryName(passport2) : "—"}</p>
      </div>
    </section>

    <section class="resultado-box" aria-label="Selected destinations">
      <h3 class="resultado-titulo-interno">Selected destinations</h3>

      <table class="multi-trip-table">
        <thead>
          <tr>
            <th>Destination</th>
            <th>Main Passport</th>
            <th>Secondary Passport</th>
            <th>Notes</th>
          </tr>
        </thead>
        <tbody>
  `;

  for (let i = 1; i <= state.destinationCount; i++) {
    const d = el(`destination${i}`)?.value || "";
    if (!d) continue;

    tableHtml += `
      <tr>
        <td>${getCountryName(d)}</td>
        <td>${visaLookup(passport1, d)}</td>
        <td>${passport2 ? visaLookup(passport2, d) : "—"}</td>
        <td>${renderNotesColumn(d, passport1, passport2)}</td>
      </tr>
    `;
  }

  tableHtml += `
        </tbody>
      </table>
    </section>
  `;

  el(DOM.multi.resultText).innerHTML = tableHtml;
  showSection(DOM.multi.resultsMain);
}

function addDestination() {
  state.destinationCount++;
  const original = el(DOM.multi.destination1);
  if (!original) return;

  const newSelect = original.cloneNode(true);
  newSelect.id = `destination${state.destinationCount}`;

  const wrapper = document.createElement("div");
  wrapper.className = "form-group";
  wrapper.id = `destination-wrap-${state.destinationCount}`;
  wrapper.innerHTML = `<label for="destination${state.destinationCount}">${state.destinationCount}º Destination:</label>`;
  wrapper.appendChild(newSelect);

  el(DOM.multi.destinationsContainer).insertBefore(wrapper, el(DOM.multi.destinationButtons));
}

function removeDestination() {
  if (state.destinationCount <= 1) return;
  el(`destination-wrap-${state.destinationCount}`)?.remove();
  state.destinationCount--;
}

/* =========================================================
  PASSPORT INFO
========================================================= */

function visaStateClass(estado) {
  const k = normalizeVisaStatus(estado);

  if (k === "not_required") return "visa-free";
  if (k === "admin_entry_req") return "admin-entry-req";
  if (k === "prior_auth") return "prior-auth";
  if (k === "visa_on_arrival") return "visa-on-arrival";
  if (k === "evisa") return "evisa";
  if (k === "required") return "visa-required";
  if (k === "entry_prohibited") return "entry-prohibited";

  return "";
}

function visaStateLabel(estado) {
  const k = normalizeVisaStatus(estado);

  if (k === "not_required") return "Visa Is Not Required";
  if (k === "admin_entry_req") return "Administrative Entry Requirement";
  if (k === "prior_auth") return "Prior Authorization";
  if (k === "visa_on_arrival") return "Visa Issued Upon Arrival";
  if (k === "evisa") return "Electronic Visa";
  if (k === "required") return "Visa Is Required";
  if (k === "entry_prohibited") return "Entry prohibited";

  return estado ? String(estado).trim() : "—";
}

function getOrCreatePassportSummaryEl() {
  const flag = el(DOM.passportInfo.flagImg);
  if (!flag?.parentElement) return null;

  let summary = flag.parentElement.querySelector("#passport-visa-summary");
  if (!summary) {
    summary = document.createElement("div");
    summary.id = "passport-visa-summary";
    summary.className = "passport-summary-box";
    flag.parentElement.appendChild(summary);
  }
  return summary;
}

function renderPassportVisaSummary(passportCode) {
  const summaryEl = getOrCreatePassportSummaryEl();
  if (!summaryEl) return;

  const destinos = [...(visaIndex.get(passportCode)?.values() || [])];
  const total = destinos.length;

  const counts = {
    visaFree: 0,
    priorAuth: 0,
    adminEntryReq: 0,
    visaOnArrival: 0,
    evisa: 0,
    visaReq: 0,
    prohibited: 0,
  };

  for (const d of destinos) {
    const k = normalizeVisaStatus(d?.estado);
    if (k === "not_required") counts.visaFree++;
    else if (k === "admin_entry_req") counts.adminEntryReq++;
    else if (k === "prior_auth") counts.priorAuth++;
    else if (k === "visa_on_arrival") counts.visaOnArrival++;
    else if (k === "evisa") counts.evisa++;
    else if (k === "required") counts.visaReq++;
    else if (k === "entry_prohibited") counts.prohibited++;
  }

  summaryEl.innerHTML = `
    <ul class="visa-summary">
      <li class="total">Total destinations: ${total}</li>

      ${counts.visaFree ? `<li class="group visa-free">Visa Is Not Required: ${counts.visaFree}</li>` : ""}
      ${counts.adminEntryReq ? `<li class="group admin-entry-req">Administrative Entry Requirement: ${counts.adminEntryReq}</li>` : ""}
      ${counts.priorAuth ? `<li class="group prior-auth">Prior Authorization: ${counts.priorAuth}</li>` : ""}
      ${counts.visaOnArrival ? `<li class="group visa-on-arrival">Visa Issued Upon Arrival: ${counts.visaOnArrival}</li>` : ""}
      ${counts.evisa ? `<li class="group evisa">Electronic Visa: ${counts.evisa}</li>` : ""}
      ${counts.visaReq ? `<li class="group visa-required">Visa Is Required: ${counts.visaReq}</li>` : ""}
      ${counts.prohibited ? `<li class="group entry-prohibited">Entry prohibited: ${counts.prohibited}</li>` : ""}
    </ul>
  `;
}

function renderPassportVisaTable(passportCode) {
  const container = el(DOM.passportInfo.tableContainer);
  const destinos = [...(visaIndex.get(passportCode)?.values() || [])];

  if (!destinos.length) {
    container.innerHTML = `<div class="info-box">No visa data for this passport.</div>`;
    return;
  }

  destinos.sort((a, b) =>
    getCountryName(a.pais).localeCompare(getCountryName(b.pais))
  );

  container.innerHTML = `
    <table class="visor-visa">
      <thead>
        <tr>
          <th>Destination</th>
          <th>Visa Status</th>
          <th>Allowed Days</th>
        </tr>
      </thead>
      <tbody>
        ${destinos
          .map((d) => {
            const statusText = visaStateLabel(d.estado);
            const cls = visaStateClass(d.estado);
            const days = Number(d.dias) > 0 ? d.dias : "—";

            return `
            <tr>
              <td>${getCountryName(d.pais)}</td>
              <td><span class="${cls}">${statusText}</span></td>
              <td>${days}</td>
            </tr>
          `;
          })
          .join("")}
      </tbody>
    </table>
  `;
}

function showPassportInfo() {
  const passportCode = el(DOM.passportInfo.select)?.value || "";
  if (!passportCode) return alert("Please select a passport.");

  const country = countries.find((c) => c.code === passportCode);
  if (!country) return alert("Country not found.");

  el(DOM.passportInfo.result).style.display = "flex";
  el(DOM.passportInfo.title).textContent = country.name;

  const flag = el(DOM.passportInfo.flagImg);
  const url = FlagImages?.[passportCode] || "";
  if (url) {
    flag.src = url;
    flag.style.display = "";
    flag.alt = `Flag of ${country.name}`;
  } else {
    flag.style.display = "none";
  }

  renderPassportVisaSummary(passportCode);
  renderPassportVisaTable(passportCode);
}

/* =========================================================
  INIT
========================================================= */
document.addEventListener("DOMContentLoaded", () => {
  populateCountrySelects();
  showSection("welcome");

  const donateEl = document.getElementById("donate-button");
  if (window.PayPal?.Donation?.Button && donateEl) {
    window.PayPal.Donation.Button({
      env: "production",
      hosted_button_id: "ZXAELQQCZDGWQ",
      image: {
        src: "https://www.paypalobjects.com/en_US/i/btn/btn_donateCC_LG.gif",
        alt: "Donate with PayPal button",
        title: "PayPal - The safer, easier way to pay online!",
      },
    }).render("#donate-button");
  }
});


window.showSection = showSection;
window.backTo = backTo;
window.goToSection = goToSection;
window.searchVisas = searchSingleTrip;
window.addConnection = addConnection;
window.removeConnection = removeConnection;
window.searchMultiTrip = searchMultiTrip;
window.addDestination = addDestination;
window.removeDestination = removeDestination;
window.showPassportInfo = showPassportInfo;
